from lfx.custom import Component
from lfx.inputs import StrInput, IntInput, MultilineInput
from lfx.template import Output
from lfx.schema import Data
import requests

class OpenMeteoForecastComponent(Component):
    display_name = "Open-Meteo Forecast"
    description = "Fetch weather forecast for a given latitude and longitude"
    icon = "cloud"

    inputs = [
        StrInput(
            name="latitude",
            display_name="Latitude",
            info="Decimal latitude, e.g. 40.3428",
            value="40.3428"
        ),
        StrInput(
            name="longitude",
            display_name="Longitude",
            info="Decimal longitude, e.g. -105.6836",
            value="-105.6836"
        ),
        IntInput(
            name="forecast_days",
            display_name="Forecast Days",
            info="Number of days to forecast (1-16)",
            value=7
        ),
        StrInput(
            name="timezone",
            display_name="Timezone",
            info="Timezone string, e.g. America/Denver",
            value="America/New_York"
        ),
        MultilineInput(
            name="daily_variables",
            display_name="Daily Variables",
            info="Comma-separated Open-Meteo daily variables to fetch",
            value="temperature_2m_max,temperature_2m_min,precipitation_sum,windspeed_10m_max,weathercode",
            tool_mode=True,
        ),
        MultilineInput(
            name="hourly_variables",
            display_name="Hourly Variables",
            info="Comma-separated Open-Meteo hourly variables (leave blank to skip)",
            value=""
        ),
    ]

    outputs = [
        Output(display_name="Forecast Tool", name="forecast", method="get_forecast")
    ]

    def get_forecast(self) -> Data:
        url = "https://api.open-meteo.com/v1/forecast"

        params = {
            "latitude": self.latitude,
            "longitude": self.longitude,
            "forecast_days": self.forecast_days,
            "timezone": self.timezone,
        }

        if self.daily_variables.strip():
            params["daily"] = self.daily_variables.strip()

        if self.hourly_variables.strip():
            params["hourly"] = self.hourly_variables.strip()

        try:
            response = requests.get(url, params=params, timeout=10)
            response.raise_for_status()
            data = response.json()

            result = {
                "location": {
                    "latitude": data.get("latitude"),
                    "longitude": data.get("longitude"),
                    "timezone": data.get("timezone"),
                    "elevation_m": data.get("elevation")
                },
                "forecast_days": self.forecast_days,
                "daily": data.get("daily", {}),
                "hourly": data.get("hourly", {})
            }

            return Data(data=result)

        except requests.exceptions.Timeout:
            return Data(data={"error": "Request timed out. Try again."})
        except requests.exceptions.HTTPError as e:
            return Data(data={"error": "HTTP error: " + str(e)})
        except Exception as e:
            return Data(data={"error": "Unexpected error: " + str(e)})

from lfx.custom import Component
from lfx.inputs import StrInput, IntInput, MultilineInput
from lfx.template import Output
from lfx.schema import Data
import requests

class NPSSearchParksComponent(Component):
    display_name = "NPS Search Parks"
    description = "Search national parks by state, activity, or keyword using the NPS API"
    icon = "map"

    inputs = [
        StrInput(
            name="state_code",
            display_name="State Code",
            info="Two-letter state code, e.g. CO, CA, NY",
            value="CO"
        ),
        SecretStrInput(
            name="api_key",
            display_name="NPS API Key",
            info="Get a free key at developer.nps.gov or use DEMO_KEY to start",
            value="DEMO_KEY"
        ),
        IntInput(
            name="limit",
            display_name="Limit",
            info="Maximum number of parks to return",
            value=5
        ),
        MultilineInput(
            name="query",
            display_name="Query",
            info="Keyword search, e.g. hiking, camping, waterfall",
            value="hiking",
            tool_mode=True,
        ),
    ]

    outputs = [
        Output(display_name="Parks Tool", name="parks", method="search_parks")
    ]

    def search_parks(self) -> Data:
        url = "https://developer.nps.gov/api/v1/parks"

        params = {
            "api_key": self.api_key,
            "limit": self.limit,
        }

        if self.state_code.strip():
            params["stateCode"] = self.state_code.strip().upper()

        if self.query.strip():
            params["q"] = self.query.strip()

        try:
            response = requests.get(url, params=params, timeout=10)
            response.raise_for_status()
            data = response.json()

            parks = []
            for p in data.get("data", []):
                parks.append({
                    "name": p.get("fullName", ""),
                    "code": p.get("parkCode", ""),
                    "description": p.get("description", "")[:200],
                    "states": p.get("states", ""),
                    "designation": p.get("designation", ""),
                    "latitude": p.get("latitude", ""),
                    "longitude": p.get("longitude", ""),
                    "url": p.get("url", "")
                })

            return Data(data={
                "total": data.get("total", len(parks)),
                "parks": parks
            })

        except requests.exceptions.Timeout:
            return Data(data={"error": "Request timed out. Try again."})
        except requests.exceptions.HTTPError as e:
            return Data(data={"error": "HTTP error: " + str(e)})
        except Exception as e:
            return Data(data={"error": "Unexpected error: " + str(e)})

from lfx.custom import Component
from lfx.inputs import StrInput, MultilineInput
from lfx.template import Output
from lfx.schema import Data
import requests

class NPSParkAlertsComponent(Component):
    display_name = "NPS Park Alerts"
    description = "Get active hazard and closure alerts for a national park"
    icon = "alert-triangle"

    inputs = [
        SecretStrInput(
            name="api_key",
            display_name="NPS API Key",
            info="Get a free key at developer.nps.gov or use DEMO_KEY to start",
            value="DEMO_KEY"
        ),
        MultilineInput(
            name="park_code",
            display_name="Park Code",
            info="Four-letter park code, e.g. romo, acad, grca, yell",
            value="romo",
            tool_mode=True,
        ),
    ]

    outputs = [
        Output(display_name="Alerts Tool", name="alerts", method="get_alerts")
    ]

    def get_alerts(self) -> Data:
        url = "https://developer.nps.gov/api/v1/alerts"

        params = {
            "api_key": self.api_key,
            "parkCode": self.park_code.strip().lower()
        }

        try:
            response = requests.get(url, params=params, timeout=10)
            response.raise_for_status()
            data = response.json()

            alerts = []
            for a in data.get("data", []):
                alerts.append({
                    "title": a.get("title", ""),
                    "category": a.get("category", ""),
                    "description": a.get("description", "")[:200],
                    "url": a.get("url", "")
                })

            return Data(data={
                "park_code": self.park_code.strip().upper(),
                "total_alerts": len(alerts),
                "alerts": alerts if alerts else ["No active alerts for this park"]
            })

        except requests.exceptions.Timeout:
            return Data(data={"error": "Request timed out. Try again."})
        except requests.exceptions.HTTPError as e:
            return Data(data={"error": "HTTP error: " + str(e)})
        except Exception as e:
            return Data(data={"error": "Unexpected error: " + str(e)})
